    // \u91CD\u7F6E\u8868\u5355\u5B57\u6BB5\u72B6\u6001
    document.getElementById('env-category').disabled = false;
    document.getElementById('env-key').readOnly = false;
    document.getElementById('value-type').disabled = false;
